#include <stdio.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        scanf("%d", &N);
        int S[1005];
        int D[1005];
        for (int i = 0; i < N; ++i) scanf("%d", &S[i]);
        for (int i = 0; i < N; ++i) scanf("%d", &D[i]);
        int ans = 0;
        for (int i = 0; i < N; ++i) if (S[i] == D[i]) ++ans;
        printf("%d\n", ans);
    }
    return 0;
}

